package com.infy.inventrack.inventory; import com.infy.inventrack.common.dto.ProductResponse; import com.infy.inventrack.inventory.client.CatalogClient; import com.infy.inventrack.inventory.entity.InventoryItem; import com.infy.inventrack.inventory.repository.InventoryRepository; import com.infy.inventrack.inventory.service.InventoryService; import org.junit.jupiter.api.Test; import java.math.BigDecimal; import java.util.*; import static org.assertj.core.api.Assertions.*; import static org.mockito.Mockito.*; class InventoryServiceTest { InventoryRepository repo=mock(InventoryRepository.class); CatalogClient client=mock(CatalogClient.class); InventoryService service=new InventoryService(repo,client); @Test void calculatesValue(){ when(repo.findAll()).thenReturn(List.of(item(5))); assertThat(service.calculateTotalInventoryValue()).isEqualTo(500.0); } @Test void reserveDecrements(){ InventoryItem i=item(10); when(client.getProduct("SKU1","auth")).thenReturn(new ProductResponse()); when(repo.findBySku("SKU1")).thenReturn(Optional.of(i)); assertThat(service.reserveStock("SKU1",3,"auth")).contains("reserved"); assertThat(i.getStockQuantity()).isEqualTo(7); } InventoryItem item(int q){ InventoryItem i=new InventoryItem(); i.setSku("SKU1"); i.setStockQuantity(q); i.setUnitPrice(new BigDecimal("100.00")); return i; } }
